var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來命運中必須要面對的，這是一個不可或缺的存在"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 연락을 하자, 곧 만나러 가겠다는 답장이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you contacted her. She said she'd come to see you soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOMI_DAYMINE_FAKE_NULL","text":{"KOREA":"저어, 사장님...... 어째서 절 이런 곳으로 불러내신 거죠?","JPN":"あの、社長……どうして私をこんなところに呼び出したのですか？","ENG":"Erm, Boss... May I ask why you called me to a place like this?","TWN":"那個，老闆……為什麼要把我叫到這個地方？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">오늘 당신에게 꼭 전해주고 싶은 말이 있어.","JPN":">今日、君に伝えたいことがあるんだ。","ENG":"> I have something to say to you today.","TWN":">今天，有件事情我必須對妳說。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOMI_DAYMINE_FAKE_NULL","text":{"KOREA":"네? 갑자기 그런 진지한 표정으로 무슨 말씀을......?","JPN":"はい？　急に真剣な顔をしてどうしたんですか……？","ENG":"Pardon? You're looking serious all of a sudden.","TWN":"什麼？你怎麼突然這麼嚴肅……？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">반지를 건낸다. [반지-1]","JPN":">指輪を渡す。[指輪 -1]","ENG":"> Give her a ring. [Ring -1]","TWN":">拿出戒指。[戒指-1]"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOMI_DAYMINE_FAKE_NULL","text":{"KOREA":"앗! 일개 직원인 저에게 이런 갑작스러운 제안을 하시다니!","JPN":"えっ！　一介の社員である私に、いきなりこのような提案をしてくださるなんて！","ENG":"Ah! This is so sudden and unexpected. I'm just an employee.","TWN":"啊！竟然會對我一個區區員工提出這種事！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOMI_DAYMINE_FAKE_NULL","text":{"KOREA":"제가 지난 번처럼 또 오해하고 있는 건 아니겠죠?","JPN":"この前のように、私の誤解ではないですよね？","ENG":"Also, I don't want to misunderstand the situation like the last time.","TWN":"該不會像上次一樣，我又誤會了吧？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣! \\n>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!","JPN":">誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！\\n>君とずっと一緒にいたいんだ！　これ以上、私を社長と呼ばないでくれ。","ENG":"[[","TWN":">不是誤會！請妳接受我的真心，茱麗葉！\\n>我想永遠和妳在一起！別再叫我老闆了！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":"<color=#ffd34c>>오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣!</color> \\n>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!","JPN":"<color=#ffd34c>>誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！</color>\\n>君とずっと一緒にいたいんだ！　これ以上、私のことを社長と呼ばないでくれ。","ENG":"[[","TWN":"<color=#ffd34c>>不是誤會！請妳接受我的真心，茱麗葉！</color>\\n>我想永遠和妳在一起！別再叫我老闆了！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣! \\n><color=#ffd34c>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!</color>","JPN":">誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！\\n><color=#ffd34c>君とずっと一緒にいたいんだ！これ以上、私のことを社長と呼ばないでくれ。</color>","ENG":"[[","TWN":">不是誤會！請妳接受我的真心，茱麗葉！\\n><color=#ffd34c>我想永遠和妳在一起！別再叫我老闆了！</color>"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":"<color=#ffd34c>>오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣!</color> \\n>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!","JPN":"<color=#ffd34c>>誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！</color>\\n>君とずっと一緒にいたいんだ！　これ以上、私のことを社長と呼ばないでくれ。","ENG":"[[","TWN":"<color=#ffd34c>>不是誤會！請妳接受我的真心，茱麗葉！</color>\\n>我想永遠和妳在一起！別再叫我老闆了！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣! \\n><color=#ffd34c>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!</color>","JPN":">誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！\\n><color=#ffd34c>君とずっと一緒にいたいんだ！　これ以上、私のことを社長と呼ばないでくれ。</color>","ENG":"[[","TWN":">不是誤會！請妳接受我的真心，茱麗葉！\\n><color=#ffd34c>我想永遠和妳在一起！別再叫我老闆了！</color>"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":"<color=#ffd34c>>오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣!</color> \\n>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!","JPN":"<color=#ffd34c>>誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！</color>\\n>君とずっと一緒にいたいんだ！　これ以上、私のことを社長と呼ばないでくれ。","ENG":"[[","TWN":"<color=#ffd34c>>不是誤會！請妳接受我的真心，茱麗葉！</color>\\n>我想永遠和妳在一起！別再叫我老闆了！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">오해라니! 그렇지 않아. 내 진심을 받아줘, 줄리엣! \\n><color=#ffd34c>너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!</color>","JPN":">誤解だなんて！　そんなことないさ。私の気持ちを受け取ってくれ、ジュリエット！\\n><color=#ffd34c>君とずっと一緒にいたいんだ！　これ以上、私のことを社長と呼ばないでくれ。</color>","ENG":"[[","TWN":">不是誤會！請妳接受我的真心，茱麗葉！\\n><color=#ffd34c>我想永遠和妳在一起！別再叫我老闆了！</color>"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PLAYER_GAME_FAKE_NULL","text":{"KOREA":">너와 영원히 함께 하고 싶어! 날 더 이상 사장님이라고 부르지 마!","JPN":">君とずっと一緒にいたいんだ！　これ以上、私のことを社長と呼ばないでくれ。","ENG":"> I want to be with you forever! Please don't call me Boss anymore!","TWN":">我想永遠和妳在一起！別再叫我老闆了！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOMI_DAYMINE_FAKE_NULL","text":{"KOREA":"아아, 그 말을 해주기만 기다리고 있었어요. ZX마왕ZX......!","JPN":"ああ、その言葉をずっと待っていました。ZX魔王ZX……！","ENG":"Ah, I've been waiting for you to say that, zxDemonLordzx!","TWN":"啊啊，我一直在等你說這句話。ZX魔王ZX……！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_FAKE_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};